// Recupera as palavras buscadas do nó anterior
const palavras = $('Montar SQL1').first().json.palavras;

// Faz o parse do resultado do banco
let candidatos = $json.candidatos;
if (typeof candidatos === 'string') {
  try { candidatos = JSON.parse(candidatos); } catch(e) { candidatos = []; }
}
if (!Array.isArray(candidatos)) { candidatos = []; }

// Retorno direto: encontrou ou não
if (candidatos.length === 0) {
  return [{ json: {
    total: 0,
    palavras_buscadas: palavras,
    candidatos: [],
    mensagem: 'Nenhum candidato encontrado para as palavras-chave informadas.'
  }}];
}

return [{ json: {
  total: candidatos.length,
  palavras_buscadas: palavras,
  candidatos
}}];

// Payload esperado:
// { "palavras": ["Desenvolvimento", "Software"], "limite": 10 }

const body = $json.body || $json;

// Aceita tanto array (novo) quanto string separada por vírgula (compatibilidade)
let palavras = body.palavras || [];
if (typeof palavras === 'string') {
  palavras = palavras.split(',').map(p => p.trim()).filter(Boolean);
}

const limite = Math.min(parseInt(body.limite) || 10, 50);

const esc = s => (s || '').replace(/'/g, "''");

// Busca full-text: cada palavra é procurada em TODOS os campos relevantes
const conditions = palavras.map(p => {
  const v = esc(p);
  return `(
    nome_completo    ILIKE '%${v}%' OR
    cargo_pretendido ILIKE '%${v}%' OR
    habilidades      ILIKE '%${v}%' OR
    localizacao      ILIKE '%${v}%' OR
    texto_curriculo  ILIKE '%${v}%'
  )`;
});

// OR entre palavras (basta 1 aparecer em qualquer campo)
const where = conditions.length ? `WHERE ${conditions.join(' OR ')}` : '';

const sql = `
  SELECT COALESCE(json_agg(row_to_json(c)), '[]'::json) AS candidatos
  FROM (
    SELECT
      telefone,
      nome_completo,
      cargo_pretendido,
      habilidades,
      localizacao,
      nome_arquivo,
      LEFT(texto_curriculo, 300) AS experiencia_resumida,
      criado_em
    FROM candidatos
    ${where}
    LIMIT ${limite}
  ) c
`;

return [{ json: { sql, palavras, limite } }];
